public class HOTELIERServer {

    private List<Hotel> hotels;

    public HOTELIERServer(String jsonFilePath) {
        loadHotelsFromJson(jsonFilePath);
    }

    private void loadHotelsFromJson(String jsonFilePath) {
        Gson gson = new Gson();
        try (FileReader reader = new FileReader(jsonFilePath)) {
            // Defining the type of the data we want to read
            Type hotelListType = new TypeToken<ArrayList<Hotel>>(){}.getType();
            // Deserializing
            hotels = gson.fromJson(reader, hotelListType);
        } catch (IOException e) {
            e.printStackTrace();
        }
    }

    // Add other functionality as needed for the HOTELIERServer

    public static void main(String[] args) {
        String jsonFilePath = "Hotels.json"; // Replace with the actual path to the JSON file
        HOTELIERServer server = new HOTELIERServer(jsonFilePath);

        // You can use the instance server to interact with the list of hotels loaded from the JSON file

        // Example: Print all hotel names
        for (Hotel hotel : server.hotels) {
            System.out.println(hotel.name);
        }
    }
}


