        seL4_Word sender_badge;  // 发送标记 地址
        seL4_Word label;  // 地址
        int vm_exit_reason; // 退出原因
        // host_endpoint: Host endoint (i.e. vmm) to wait for VM faults and host events
        tag = seL4_Recv(vm->host_endpoint, &sender_badge); // 阻塞直到在端点上接收到消息。  参数： 要调用的能力。， 发送人要发送的信息的写入地址。发送者的信息是发送者调用的端点能力的标记，或者是发出信号的通知对象的通知字。如果 ，则忽略此参数NULL。
        label = seL4_MessageInfo_get_label(tag);
        if (sender_badge >= MIN_VCPU_BADGE && sender_badge <= MAX_VCPU_BADGE) { // >= 1; <= 4。则成功接受msg，并写入到
            seL4_Word vcpu_idx = VCPU_BADGE_IDX(sender_badge); // 减一（得索引）
            if (vcpu_idx >= vm->num_vcpus) { // 无此索引， 不能是第1个vcpu
                ZF_LOGE("Invalid VCPU index. Exiting");
                ret = -1;
            } else { // 小于0  Fault
                vm_exit_reason = vm_decode_exit(label);
                ret = arm_exit_handlers[vm_exit_reason](vm->vcpus[vcpu_idx]);
                if (ret == VM_EXIT_HANDLE_ERROR) {
                    vm->run.exit_reason = VM_GUEST_ERROR_EXIT;
                }
            }
        } else { // 接受消息
            if (vm->run.notification_callback) { //   调用消息回调函数
                err = vm->run.notification_callback(vm, sender_badge, tag,   // ！！处理消息的关键函数
                                                    vm->run.notification_callback_cookie);
            } else {
                ZF_LOGE("Unable to handle VM notification. Exiting");
                err = -1;
            }
            if (err) {
                ret = -1;
                vm->run.exit_reason = VM_GUEST_ERROR_EXIT;
            }
        }
    }

    return ret;
}
